#!/bin/bash
# Generated by cc-statusline v1.4.0 (https://www.npmjs.com/package/@chongdashu/cc-statusline)
# Custom Claude Code statusline - Created: 2026-01-05T17:12:22.021Z
# Theme: detailed | Colors: true | Features: directory, git, model, context, usage, tokens, burnrate, session
STATUSLINE_VERSION="1.4.0"

input=$(cat)

# ---- check jq availability ----
HAS_JQ=0
if command -v jq >/dev/null 2>&1; then
  HAS_JQ=1
fi

# ---- color helpers (force colors for Claude Code) ----
use_color=1
[ -n "$NO_COLOR" ] && use_color=0

C() { if [ "$use_color" -eq 1 ]; then printf '\033[%sm' "$1"; fi; }
RST() { if [ "$use_color" -eq 1 ]; then printf '\033[0m'; fi; }

# ---- modern sleek colors ----
dir_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;117m'; fi; }    # sky blue
model_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;147m'; fi; }  # light purple  
version_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;180m'; fi; } # soft yellow
cc_version_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;249m'; fi; } # light gray
style_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;245m'; fi; } # gray
rst() { if [ "$use_color" -eq 1 ]; then printf '\033[0m'; fi; }

# ---- time helpers ----
to_epoch() {
  ts="$1"
  if command -v gdate >/dev/null 2>&1; then gdate -d "$ts" +%s 2>/dev/null && return; fi
  date -u -j -f "%Y-%m-%dT%H:%M:%S%z" "${ts/Z/+0000}" +%s 2>/dev/null && return
  python3 - "$ts" <<'PY' 2>/dev/null
import sys, datetime
s=sys.argv[1].replace('Z','+00:00')
print(int(datetime.datetime.fromisoformat(s).timestamp()))
PY
}

fmt_time_hm() {
  epoch="$1"
  if date -r 0 +%s >/dev/null 2>&1; then date -r "$epoch" +"%H:%M"; else date -d "@$epoch" +"%H:%M"; fi
}

progress_bar() {
  pct="${1:-0}"; width="${2:-10}"
  [[ "$pct" =~ ^[0-9]+$ ]] || pct=0; ((pct<0))&&pct=0; ((pct>100))&&pct=100
  filled=$(( pct * width / 100 )); empty=$(( width - filled ))
  printf '%*s' "$filled" '' | tr ' ' '='
  printf '%*s' "$empty" '' | tr ' ' '-'
}

# git utilities
num_or_zero() { v="$1"; [[ "$v" =~ ^[0-9]+$ ]] && echo "$v" || echo 0; }

# ---- JSON extraction utilities ----
# Pure bash JSON value extractor (fallback when jq not available)
extract_json_string() {
  local json="$1"
  local key="$2"
  local default="${3:-}"
  
  # For nested keys like workspace.current_dir, get the last part
  local field="${key##*.}"
  field="${field%% *}"  # Remove any jq operators
  
  # Try to extract string value (quoted)
  local value=$(echo "$json" | grep -o "\"\${field}\"[[:space:]]*:[[:space:]]*\"[^\"]*\"" | head -1 | sed 's/.*:[[:space:]]*"\([^"]*\)".*/\1/')
  
  # Convert escaped backslashes to forward slashes for Windows paths
  if [ -n "$value" ]; then
    value=$(echo "$value" | sed 's/\\\\/\//g')
  fi
  
  # If no string value found, try to extract number value (unquoted)
  if [ -z "$value" ] || [ "$value" = "null" ]; then
    value=$(echo "$json" | grep -o "\"\${field}\"[[:space:]]*:[[:space:]]*[0-9.]\+" | head -1 | sed 's/.*:[[:space:]]*\([0-9.]\+\).*/\1/')
  fi
  
  # Return value or default
  if [ -n "$value" ] && [ "$value" != "null" ]; then
    echo "$value"
  else
    echo "$default"
  fi
}

# ---- basics ----
if [ "$HAS_JQ" -eq 1 ]; then
  current_dir=$(echo "$input" | jq -r '.workspace.current_dir // .cwd // "unknown"' 2>/dev/null | sed "s|^$HOME|~|g")
  model_name=$(echo "$input" | jq -r '.model.display_name // "Claude"' 2>/dev/null)
  model_version=$(echo "$input" | jq -r '.model.version // ""' 2>/dev/null)
  session_id=$(echo "$input" | jq -r '.session_id // ""' 2>/dev/null)
  cc_version=$(echo "$input" | jq -r '.version // ""' 2>/dev/null)
  output_style=$(echo "$input" | jq -r '.output_style.name // ""' 2>/dev/null)
else
  # Bash fallback for JSON extraction
  # Extract current_dir from workspace object - look for the pattern workspace":{"current_dir":"..."}
  current_dir=$(echo "$input" | grep -o '"workspace"[[:space:]]*:[[:space:]]*{[^}]*"current_dir"[[:space:]]*:[[:space:]]*"[^"]*"' | sed 's/.*"current_dir"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/' | sed 's/\\\\/\//g')
  
  # Fall back to cwd if workspace extraction failed
  if [ -z "$current_dir" ] || [ "$current_dir" = "null" ]; then
    current_dir=$(echo "$input" | grep -o '"cwd"[[:space:]]*:[[:space:]]*"[^"]*"' | sed 's/.*"cwd"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/' | sed 's/\\\\/\//g')
  fi
  
  # Fallback to unknown if all extraction failed
  [ -z "$current_dir" ] && current_dir="unknown"
  current_dir=$(echo "$current_dir" | sed "s|^$HOME|~|g")
  
  # Extract model name from nested model object
  model_name=$(echo "$input" | grep -o '"model"[[:space:]]*:[[:space:]]*{[^}]*"display_name"[[:space:]]*:[[:space:]]*"[^"]*"' | sed 's/.*"display_name"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/')
  [ -z "$model_name" ] && model_name="Claude"
  # Model version is in the model ID, not a separate field  
  model_version=""  # Not available in Claude Code JSON
  session_id=$(extract_json_string "$input" "session_id" "")
  # CC version is at the root level
  cc_version=$(echo "$input" | grep -o '"version"[[:space:]]*:[[:space:]]*"[^"]*"' | head -1 | sed 's/.*"version"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/')
  # Output style is nested
  output_style=$(echo "$input" | grep -o '"output_style"[[:space:]]*:[[:space:]]*{[^}]*"name"[[:space:]]*:[[:space:]]*"[^"]*"' | sed 's/.*"name"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/')
fi

# ---- git colors ----
git_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;150m'; fi; }  # soft green
rst() { if [ "$use_color" -eq 1 ]; then printf '\033[0m'; fi; }

# ---- git ----
git_branch=""
if git rev-parse --git-dir >/dev/null 2>&1; then
  git_branch=$(git branch --show-current 2>/dev/null || git rev-parse --short HEAD 2>/dev/null)
fi

# ---- context window calculation (native) ----
context_pct=""
context_remaining_pct=""
context_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;37m'; fi; }  # default white

if [ "$HAS_JQ" -eq 1 ]; then
  # Get context window size and current usage from native Claude Code input
  CONTEXT_SIZE=$(echo "$input" | jq -r '.context_window.context_window_size // 200000' 2>/dev/null)
  USAGE=$(echo "$input" | jq '.context_window.current_usage' 2>/dev/null)

  if [ "$USAGE" != "null" ] && [ -n "$USAGE" ]; then
    # Calculate current context from current_usage fields
    # Formula: input_tokens + cache_creation_input_tokens + cache_read_input_tokens
    CURRENT_TOKENS=$(echo "$USAGE" | jq '(.input_tokens // 0) + (.cache_creation_input_tokens // 0) + (.cache_read_input_tokens // 0)' 2>/dev/null)

    if [ -n "$CURRENT_TOKENS" ] && [ "$CURRENT_TOKENS" -gt 0 ] 2>/dev/null; then
      context_used_pct=$(( CURRENT_TOKENS * 100 / CONTEXT_SIZE ))
      # Clamp to valid range
      (( context_used_pct < 0 )) && context_used_pct=0
      (( context_used_pct > 100 )) && context_used_pct=100

      # Set color based on used percentage
      if [ "$context_used_pct" -ge 70 ]; then
        context_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;203m'; fi; }  # red
      elif [ "$context_used_pct" -ge 50 ]; then
        context_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;215m'; fi; }  # orange
      elif [ "$context_used_pct" -ge 30 ]; then
        context_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;228m'; fi; }  # yellow
      else
        context_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;158m'; fi; }  # green
      fi

      context_pct="${context_used_pct}%"
    fi
  fi
fi

# ---- usage colors ----
usage_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;189m'; fi; }  # lavender
cost_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;222m'; fi; }   # light gold
burn_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;220m'; fi; }   # bright gold
session_color() {
  if   (( session_pct >= 90 )); then SCLR='38;5;203'   # red >=90%
  elif (( session_pct >= 70 )); then SCLR='38;5;228'   # yellow >=70%
  else                               SCLR='38;5;158'; fi  # green <70%
  if [ "$use_color" -eq 1 ]; then printf '\033[%sm' "$SCLR"; fi
}

# ---- cost and usage extraction ----
session_txt=""; session_pct=0; session_bar=""
cost_usd=""; cost_per_hour=""; tpm=""; tot_tokens=""

# Extract cost and token data from Claude Code's native input
if [ "$HAS_JQ" -eq 1 ]; then
  # Cost data
  cost_usd=$(echo "$input" | jq -r '.cost.total_cost_usd // empty' 2>/dev/null)
  total_duration_ms=$(echo "$input" | jq -r '.cost.total_duration_ms // empty' 2>/dev/null)

  # Calculate burn rate ($/hour) from cost and duration
  if [ -n "$cost_usd" ] && [ -n "$total_duration_ms" ] && [ "$total_duration_ms" -gt 0 ]; then
    cost_per_hour=$(echo "$cost_usd $total_duration_ms" | awk '{printf "%.2f", $1 * 3600000 / $2}')
  fi

  # Token data from native context_window (no ccusage needed)
  input_tokens=$(echo "$input" | jq -r '.context_window.total_input_tokens // 0' 2>/dev/null)
  output_tokens=$(echo "$input" | jq -r '.context_window.total_output_tokens // 0' 2>/dev/null)

  if [ "$input_tokens" != "null" ] && [ "$output_tokens" != "null" ]; then
    tot_tokens=$(( input_tokens + output_tokens ))
    [ "$tot_tokens" -eq 0 ] && tot_tokens=""
  fi

  # Calculate tokens per minute from native data
  if [ -n "$tot_tokens" ] && [ -n "$total_duration_ms" ] && [ "$total_duration_ms" -gt 0 ]; then
    # Convert ms to minutes and calculate rate
    tpm=$(echo "$tot_tokens $total_duration_ms" | awk '{if ($2 > 0) printf "%.0f", $1 * 60000 / $2; else print ""}')
  fi
else
  # Bash fallback for cost extraction
  cost_usd=$(echo "$input" | grep -o '"total_cost_usd"[[:space:]]*:[[:space:]]*[0-9.]*' | sed 's/.*:[[:space:]]*\([0-9.]*\).*/\1/')
  total_duration_ms=$(echo "$input" | grep -o '"total_duration_ms"[[:space:]]*:[[:space:]]*[0-9]*' | sed 's/.*:[[:space:]]*\([0-9]*\).*/\1/')

  # Calculate burn rate ($/hour) from cost and duration
  if [ -n "$cost_usd" ] && [ -n "$total_duration_ms" ] && [ "$total_duration_ms" -gt 0 ]; then
    cost_per_hour=$(echo "$cost_usd $total_duration_ms" | awk '{printf "%.2f", $1 * 3600000 / $2}')
  fi

  # Token data from native context_window (bash fallback)
  input_tokens=$(echo "$input" | grep -o '"total_input_tokens"[[:space:]]*:[[:space:]]*[0-9]*' | sed 's/.*:[[:space:]]*\([0-9]*\).*/\1/')
  output_tokens=$(echo "$input" | grep -o '"total_output_tokens"[[:space:]]*:[[:space:]]*[0-9]*' | sed 's/.*:[[:space:]]*\([0-9]*\).*/\1/')

  if [ -n "$input_tokens" ] && [ -n "$output_tokens" ]; then
    tot_tokens=$(( input_tokens + output_tokens ))
    [ "$tot_tokens" -eq 0 ] && tot_tokens=""
  fi

  # Calculate tokens per minute from native data
  if [ -n "$tot_tokens" ] && [ -n "$total_duration_ms" ] && [ "$total_duration_ms" -gt 0 ]; then
    tpm=$(echo "$tot_tokens $total_duration_ms" | awk '{if ($2 > 0) printf "%.0f", $1 * 60000 / $2; else print ""}')
  fi
fi

# ---- token expiry (from credentials file) ----
token_txt=""; token_pct=0; token_bar=""
token_color() {
  if [ "$use_color" -eq 1 ]; then printf '\033[38;5;194m'; fi  # default green
}

CREDS_FILE="$HOME/.claude/.credentials.json"
if [ -f "$CREDS_FILE" ] && [ "$HAS_JQ" -eq 1 ]; then
  expires_ms=$(jq -r '.claudeAiOauth.expiresAt // empty' "$CREDS_FILE" 2>/dev/null)

  if [ -n "$expires_ms" ]; then
    expires_sec=$(( expires_ms / 1000 ))
    now_sec=$(date +%s)
    token_remaining=$(( expires_sec - now_sec ))

    if [ "$token_remaining" -le 0 ]; then
      token_txt="EXPIRED"
      token_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;203m'; fi; }
    else
      token_expiry_hm=$(fmt_time_hm "$expires_sec")
      if [ "$token_remaining" -lt 3600 ]; then
        token_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;203m'; fi; }  # red <1h
      elif [ "$token_remaining" -lt 7200 ]; then
        token_color() { if [ "$use_color" -eq 1 ]; then printf '\033[38;5;228m'; fi; }  # yellow <2h
      fi
      token_txt="$(token_color)●$(rst) Expires $token_expiry_hm"
    fi
  fi
fi

# ---- rate limits (native from Claude Code stdin, available since v2.1.80) ----
if [ "$HAS_JQ" -eq 1 ]; then
  five_hr_pct=$(echo "$input" | jq -r '.rate_limits.five_hour.used_percentage // empty' 2>/dev/null)
  five_hr_reset=$(echo "$input" | jq -r '.rate_limits.five_hour.resets_at // empty' 2>/dev/null)
  seven_day_pct=$(echo "$input" | jq -r '.rate_limits.seven_day.used_percentage // empty' 2>/dev/null)

  if [ -n "$five_hr_pct" ]; then
    session_pct=$(printf '%.0f' "$five_hr_pct")
    session_bar=$(progress_bar "$session_pct" 10)

    if [ -n "$five_hr_reset" ]; then
      now_sec=$(date +%s)
      remaining=$(( five_hr_reset - now_sec )); (( remaining < 0 )) && remaining=0
      rh=$(( remaining / 3600 )); rm=$(( (remaining % 3600) / 60 ))
      end_hm=$(fmt_time_hm "$five_hr_reset")
      session_time="$(printf '%dh %dm left' "$rh" "$rm")"
      session_reset="$(printf 'Reset @ %s' "$end_hm")"
      session_txt="$(printf '%s · %d%% [%s] · %s' "$session_time" "$session_pct" "$session_bar" "$session_reset")"
      session_bar=""
    else
      session_txt="$(printf '%d%% [%s]' "$session_pct" "$session_bar")"
      session_bar=""
    fi
  fi

  if [ -n "$seven_day_pct" ]; then
    weekly_pct=$(printf '%.0f' "$seven_day_pct")
  fi
fi


# ---- extended git info ----
git_ahead=""
git_behind=""
git_staged=0
git_modified=0
git_untracked=0
if [ -n "$git_branch" ]; then
  # Ahead/behind remote
  upstream=$(git rev-parse --abbrev-ref --symbolic-full-name '@{u}' 2>/dev/null)
  if [ -n "$upstream" ]; then
    git_ahead=$(git rev-list --count "${upstream}..HEAD" 2>/dev/null)
    git_behind=$(git rev-list --count "HEAD..${upstream}" 2>/dev/null)
  fi
  # Working tree status counts
  while IFS= read -r line; do
    xy="${line:0:2}"
    x="${xy:0:1}"
    y="${xy:1:1}"
    [ "$x" = "?" ] && (( git_untracked++ )) && continue
    [ "$x" != " " ] && [ "$x" != "?" ] && (( git_staged++ ))
    [ "$y" != " " ] && [ "$y" != "?" ] && (( git_modified++ ))
  done < <(git status --porcelain 2>/dev/null)
fi

# ---- profile badge ----
profile_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;255m'; fi; }  # bold white

# ---- render statusline ----
# Line 1: Profile badge (if set) + directory + model + version + style
if [ -n "${CLAUDE_PROFILE:-}" ]; then
  case "${CLAUDE_PROFILE^^}" in
    PSD*)      badge_bg='\033[48;5;22m';  badge_label=" PSD " ;;       # dark forest green bg
    PERSONAL*) badge_bg='\033[48;5;91m';  badge_label=" Personal " ;;  # purple bg
    *)         badge_bg='\033[48;5;236m'; badge_label=" ${CLAUDE_PROFILE} " ;;
  esac
  if [ "$use_color" -eq 1 ]; then
    printf '%b\033[1;38;5;255m%s\033[0m' "$badge_bg" "$badge_label"
  else
    printf '[%s]' "$CLAUDE_PROFILE"
  fi
  printf '  '
fi
printf '📁 %s%s%s' "$(dir_color)" "$current_dir" "$(rst)"
printf '  🤖 %s%s%s' "$(model_color)" "$model_name" "$(rst)"
if [ -n "$model_version" ] && [ "$model_version" != "null" ]; then
  printf '  🏷️ %s%s%s' "$(version_color)" "$model_version" "$(rst)"
fi
if [ -n "$cc_version" ] && [ "$cc_version" != "null" ]; then
  printf '  📟 %sv%s%s' "$(cc_version_color)" "$cc_version" "$(rst)"
fi
if [ -n "$output_style" ] && [ "$output_style" != "null" ]; then
  printf '  🎨 %s%s%s' "$(style_color)" "$output_style" "$(rst)"
fi

# Line 2: Git info
if [ -n "$git_branch" ]; then
  printf '\n🌿 %s%s%s' "$(git_color)" "$git_branch" "$(rst)"
  # Ahead/behind
  if [ -n "$git_ahead" ] && [ -n "$git_behind" ]; then
    [ "$git_ahead" -gt 0 ] && printf '  %s↑%s%s' "$(git_color)" "$git_ahead" "$(rst)"
    [ "$git_behind" -gt 0 ] && printf '  %s↓%s%s' "$(git_color)" "$git_behind" "$(rst)"
  fi
  # Staged / modified / untracked
  [ "$git_staged" -gt 0 ]   && printf '  %s●%s staged:%s%s' "$(git_color)" "$(rst)" "$git_staged" "$(rst)"
  [ "$git_modified" -gt 0 ] && printf '  %s~%s modified:%s%s' "$(git_color)" "$(rst)" "$git_modified" "$(rst)"
  [ "$git_untracked" -gt 0 ] && printf '  %s?%s untracked:%s%s' "$(git_color)" "$(rst)" "$git_untracked" "$(rst)"
fi

# Line 3: Context + auth token
line3=""
if [ -n "$context_pct" ]; then
  context_bar=$(progress_bar "$context_used_pct" 10)
  line3="🧠 $(context_color)Context Used: ${context_pct} [${context_bar}]$(rst)"
else
  line3="🧠 $(context_color)Context Used: TBD$(rst)"
fi
if [ -n "$token_txt" ]; then
  line3="$line3  🔑 $(token_color)${token_txt}$(rst)"
fi

# Line 4: Token usage + cost + session reset
line4=""
if [ -n "$tot_tokens" ] && [[ "$tot_tokens" =~ ^[0-9]+$ ]]; then
  if [ -n "$tpm" ] && [[ "$tpm" =~ ^[0-9.]+$ ]]; then
    tpm_formatted=$(printf '%.0f' "$tpm")
    line4="📊 $(usage_color)${tot_tokens} tok (${tpm_formatted} tpm)$(rst)"
  else
    line4="📊 $(usage_color)${tot_tokens} tok$(rst)"
  fi
fi

# Cost display
cost_txt=""
if [ -n "$cost_usd" ] && [[ "$cost_usd" =~ ^[0-9.]+$ ]]; then
  cost_fmt=$(printf '$%.4f' "$cost_usd")
  if [ -n "$cost_per_hour" ] && [[ "$cost_per_hour" =~ ^[0-9.]+$ ]]; then
    cph_fmt=$(printf '$%.2f/hr' "$cost_per_hour")
    cost_txt="$(cost_color)${cost_fmt} · ${cph_fmt}$(rst)"
  else
    cost_txt="$(cost_color)${cost_fmt}$(rst)"
  fi
fi
if [ -n "$cost_txt" ]; then
  if [ -n "$line4" ]; then
    line4="$line4  💰 ${cost_txt}"
  else
    line4="💰 ${cost_txt}"
  fi
fi

# Session limit line (personal profile only — set SHOW_SESSION_LIMIT=1 in settings.json env)
line_session=""
if [ "${SHOW_SESSION_LIMIT:-0}" = "1" ] && [ -n "$five_hr_pct" ]; then
  sl_pct=$(printf '%.0f' "$five_hr_pct")
  sl_bar=$(progress_bar "$sl_pct" 12)

  # Color: green → yellow → orange → red
  sl_color() {
    if   (( sl_pct >= 90 )); then printf '\033[38;5;203m'  # red
    elif (( sl_pct >= 70 )); then printf '\033[38;5;215m'  # orange
    elif (( sl_pct >= 40 )); then printf '\033[38;5;228m'  # yellow
    else                          printf '\033[38;5;158m'; fi  # green
  }
  if [ "$use_color" -ne 1 ]; then sl_color() { :; }; fi

  sl_txt="$(sl_color)${sl_pct}% [${sl_bar}]$(rst)"

  if [ -n "$five_hr_reset" ]; then
    now_sec=$(date +%s)
    remaining=$(( five_hr_reset - now_sec )); (( remaining < 0 )) && remaining=0
    rh=$(( remaining / 3600 )); rm=$(( (remaining % 3600) / 60 ))
    end_hm=$(fmt_time_hm "$five_hr_reset")
    sl_txt="$sl_txt  $(sl_color)${rh}h ${rm}m left · resets ${end_hm}$(rst)"
  fi

  # Also show 7-day if available
  if [ -n "${weekly_pct:-}" ]; then
    wk_bar=$(progress_bar "$weekly_pct" 8)
    sl_txt="$sl_txt  $(sl_color)7d: ${weekly_pct}% [${wk_bar}]$(rst)"
  fi

  line_session="⏱ Session: ${sl_txt}"
elif [ -n "$session_txt" ]; then
  # Fallback: append to line4 when SHOW_SESSION_LIMIT is not set
  if [ -n "$line4" ]; then
    line4="$line4  ⌛ $(session_color)${session_txt}$(rst)"
  else
    line4="⌛ $(session_color)${session_txt}$(rst)"
  fi
fi

# Print lines
if [ -n "$line3" ]; then
  printf '\n%s' "$line3"
fi
if [ -n "$line4" ]; then
  printf '\n%s' "$line4"
fi
if [ -n "$line_session" ]; then
  printf '\n%s' "$line_session"
fi
printf '\n'
